1	<title>Fitness Cartel: FAQs for Top 5 Locations</title>
2	<style>
3	@font-face {
4	  font-family: 'Fraction';
5	  src: local('Arial Narrow Bold'), local('Arial');
6	  font-weight: 800;
7	}
8	:root {
9	  --paper: #f2f5f2;
10	  --paper-2: #e7ece7;
11	  --ink: #10160f;
12	  --ink-soft: #45524a;
13	  --line: #d3dcd2;
14	  --accent: #ff4327;
15	  --teal: #0b7d72;
16	  --teal-soft: #e3f2ef;
17	  --card: #ffffff;
18	  --shadow: 0 1px 2px rgba(16,22,15,0.06);
19	}
20	@media (prefers-color-scheme: dark) {
21	  :root {
22	    --paper: #12140f; --paper-2: #191c15; --ink: #eef1ea; --ink-soft: #a6b0a0;
23	    --line: #2b2f26; --accent: #ff5a3d; --teal: #3fd6c4; --teal-soft: #10231f;
24	    --card: #181b14; --shadow: 0 1px 2px rgba(0,0,0,0.4);
25	  }
26	}
27	:root[data-theme="dark"] {
28	  --paper: #12140f; --paper-2: #191c15; --ink: #eef1ea; --ink-soft: #a6b0a0;
29	  --line: #2b2f26; --accent: #ff5a3d; --teal: #3fd6c4; --teal-soft: #10231f;
30	  --card: #181b14; --shadow: 0 1px 2px rgba(0,0,0,0.4);
31	}
32	:root[data-theme="light"] {
33	  --paper: #f2f5f2; --paper-2: #e7ece7; --ink: #10160f; --ink-soft: #45524a;
34	  --line: #d3dcd2; --accent: #ff4327; --teal: #0b7d72; --teal-soft: #e3f2ef;
35	  --card: #ffffff; --shadow: 0 1px 2px rgba(16,22,15,0.06);
36	}
37	* { box-sizing: border-box; }
38	body { background: var(--paper); color: var(--ink); font-family: 'Inter','Segoe UI',system-ui,sans-serif; margin: 0; }
39	.wrap { max-width: 900px; margin: 0 auto; padding: 44px 22px 80px; }
40	.eyebrow { font-family: 'Arial Narrow','Oswald',system-ui,sans-serif; font-weight: 800; letter-spacing: .14em; text-transform: uppercase; font-size: 12.5px; color: var(--accent); margin: 0 0 10px; }
41	h1 { font-family: 'Arial Narrow','Oswald',system-ui,sans-serif; font-weight: 800; font-size: clamp(28px,4.2vw,42px); line-height: 1.05; letter-spacing: -.01em; margin: 0 0 14px; text-wrap: balance; text-transform: uppercase; }
42	.dek { font-size: 16px; line-height: 1.6; color: var(--ink-soft); max-width: 68ch; margin: 0 0 28px; }
43	.rank-strip { display: flex; flex-wrap: wrap; gap: 10px; margin-bottom: 30px; }
44	.rank-chip { background: var(--card); border: 1px solid var(--line); border-radius: 3px; padding: 9px 13px; font-size: 12.5px; color: var(--ink-soft); box-shadow: var(--shadow); display: flex; align-items: center; gap: 7px; }
45	.rank-chip b { color: var(--ink); font-variant-numeric: tabular-nums; }
46	.rank-chip .r { color: var(--teal); font-weight: 700; font-variant-numeric: tabular-nums; }
47	.callout { background: var(--teal-soft); border-left: 3px solid var(--teal); border-radius: 0 4px 4px 0; padding: 14px 18px; font-size: 14px; line-height: 1.6; margin-bottom: 38px; }
48	.callout strong { color: var(--ink); }
49	
50	.club { margin-bottom: 44px; }
51	.club-head { display: flex; align-items: baseline; justify-content: space-between; flex-wrap: wrap; gap: 8px 16px; border-bottom: 2px solid var(--ink); padding-bottom: 10px; margin-bottom: 6px; }
52	.club-name { font-family: 'Arial Narrow','Oswald',system-ui,sans-serif; font-weight: 800; text-transform: uppercase; letter-spacing: .02em; font-size: 22px; }
53	.club-stat { font-size: 12.5px; color: var(--ink-soft); font-variant-numeric: tabular-nums; }
54	.club-stat b { color: var(--teal); }
55	.club-meta { font-size: 12.5px; color: var(--ink-soft); margin: 0 0 18px; line-height: 1.6; }
56	
57	details.faq { background: var(--card); border: 1px solid var(--line); border-radius: 6px; margin-bottom: 8px; box-shadow: var(--shadow); overflow: hidden; }
58	details.faq summary { list-style: none; cursor: pointer; padding: 14px 44px 14px 16px; font-weight: 650; font-size: 14.5px; position: relative; }
59	details.faq summary::-webkit-details-marker { display: none; }
60	details.faq summary::after { content: '+'; position: absolute; right: 16px; top: 50%; transform: translateY(-50%); color: var(--accent); font-size: 20px; font-weight: 400; line-height: 1; }
